vec4 composite( vec4 a, vec4 b) {
    return a * (1. - b.a) + b;
}



    mat2 rot2(float a) {
        float c = cos(a);
        float s = sin(a);
        return mat2(c, -s, s, c);
    }

    vec2 l2s( vec2 v ) {
        return (vec4(v,0.,1.)*acLayerToScreen).xy;
    }

    void main() {

        vec2 st = acLayerNorm;
        st -= 0.5;
        st.x *= acLayerSize.x/acLayerSize.y;
        st /= scale;
        st.x /= acLayerSize.x/acLayerSize.y;
        st += 0.5;

        vec2 sampleCoord = l2s(st);

        if( sample == 0 ) {
            sampleCoord *= acScreenSize;
            sampleCoord = floor(sampleCoord) + 0.5;
            sampleCoord /= acScreenSize;
        }

        vec4 scaledTexColor = texture2DCv(comp.texture,sampleCoord);
        if( scaleMask ) {
            vec4 baseColor = texture2DCv(inputImg.texture,sampleCoord);
            gl_FragColor = scaledTexColor*baseColor.a;
        } else {
            vec4 baseColor = texture2DCv(inputImg.texture,acScreenNorm);
            gl_FragColor = scaledTexColor*baseColor.a;
        }

    }
